package dev.codedefense.application;
import dev.codedefense.cli.ExitCodes;import dev.codedefense.domain.*;import dev.codedefense.passport.*;import java.io.PrintWriter;import java.nio.file.Path;import java.time.*;import java.util.*;
public final class CreateChangeHandoffUseCase {private final ChangePassportStore passports;private final ChangeHandoffJsonCodec codec;private final ChangeHandoffFileStore files;private final Clock clock;private final java.util.function.Supplier<String> ids;
 public CreateChangeHandoffUseCase(ChangePassportStore p,ChangeHandoffJsonCodec c,ChangeHandoffFileStore f,Clock clock,java.util.function.Supplier<String> ids){this.passports=Objects.requireNonNull(p);this.codec=Objects.requireNonNull(c);this.files=Objects.requireNonNull(f);this.clock=Objects.requireNonNull(clock);this.ids=Objects.requireNonNull(ids);}
 public int create(Path repository,Path output,boolean overwrite,PrintWriter out,PrintWriter err){var latest=passports.readLatest();if(latest.isEmpty()){err.println("No Change Passport is available for handoff.");return ExitCodes.NO_SUPPORTED_SOURCE_FILES;}var receipt=latest.orElseThrow().receipt();List<PassportAttemptSummary> attempts=passports.listByFingerprint(receipt.diffFingerprint(),20).stream().map(StoredChangePassport::receipt).map(PassportReceipt::attemptSummary).toList().reversed();ChangeHandoff handoff=new ChangeHandoff(1,ids.get(),Instant.now(clock),receipt.repositoryIdentityHash(),receipt.changeKind(),receipt.baseCommit(),receipt.sourceIdentity(),receipt.diffFingerprint(),attempts,"0".repeat(64));Path written=files.write(output,codec.encode(handoff),overwrite);out.println("Change Handoff created: "+written.getFileName());out.println("Source content included: no");return ExitCodes.SUCCESS;}}
